from __future__ import annotations

from scripts.tasklib import branch_name, normalize_task


def make_task(
    task_id: str,
    title: str,
    task_type: str,
    phase: int,
    files: list[str],
    dependencies: list[str],
    success_criteria: list[str],
    priority: str = "medium",
) -> dict:
    task = {
        "id": task_id,
        "title": title,
        "type": task_type,
        "phase": phase,
        "files": files,
        "dependencies": dependencies,
        "status": "pending",
        "success_criteria": success_criteria,
        "priority": priority,
    }
    task["branch"] = branch_name(task)
    return normalize_task(task)


